stairs_positions = []
for y, line in enumerate(map_lines):
    for x, char in enumerate(line):
        if char == '>':
            # x is column position in the line (need to skip leading spaces)
            stairs_positions.append((x, y, line))

print("Stairs found:", stairs_positions)
